// TestStatusTransitionsForProposed locks down the documented state machine:
// proposed → open and proposed → cancelled are allowed; everything else
// out of proposed is rejected. Callers (UI approval flow) rely on this
// envelope to decide which buttons to enable.
func TestStatusTransitionsForProposed(t *testing.T) {
	cases := []struct {
		from, to string
		want     bool
	}{
		{StatusProposed, StatusOpen, true},
		{StatusProposed, StatusCancelled, true},
		{StatusProposed, StatusInProgress, false},
		{StatusProposed, StatusClosed, false},
		{StatusProposed, StatusBlocked, false},
		{StatusProposed, StatusProposed, false},
		{StatusOpen, StatusInProgress, true},
		{StatusInProgress, StatusClosed, true},
		// closed and cancelled are terminal per TD-031 §3; reopening
		// is filing a follow-up bead, not a transition.
		{StatusClosed, StatusOpen, false},
		{StatusCancelled, StatusOpen, false},
		{"", StatusOpen, false},
		{StatusOpen, "", false},
		{"bogus", StatusOpen, false},
	}
	for _, tc := range cases {
		t.Run(tc.from+"->"+tc.to, func(t *testing.T) {
			assert.Equal(t, tc.want, IsValidStatusTransition(tc.from, tc.to))
		})
	}
}

// IsValidStatusTransition reports whether a bead may move from `from` to `to`
// under the documented state machine. Self-transitions (from == to) and
// transitions to/from the empty string (used by Create defaults) are rejected;
// callers that want to seed a fresh status should set b.Status directly before
// validateBead runs.
//
// The matrix below is the normative implementation of TD-031 §3 (Transition
// Matrix). `closed` and `cancelled` are terminal — re-opening a closed bead
// is not a transition; it is filing a follow-up bead with `replaces` set.
//
// Allowed transitions:
//
//	proposed    → open, cancelled
//	open        → in_progress, blocked, cancelled
//	in_progress → open, closed, blocked
//	blocked     → open, cancelled
//	closed      → (terminal)
//	cancelled   → (terminal)
func IsValidStatusTransition(from, to string) bool {
	if from == "" || to == "" || from == to {
		return false
	}
	allowed := map[string]map[string]bool{
		StatusProposed:   {StatusOpen: true, StatusCancelled: true},
		StatusOpen:       {StatusInProgress: true, StatusBlocked: true, StatusCancelled: true},
		StatusInProgress: {StatusOpen: true, StatusClosed: true, StatusBlocked: true},
		StatusBlocked:    {StatusOpen: true, StatusCancelled: true},
		StatusClosed:     {},
		StatusCancelled:  {},
	}
	if next, ok := allowed[from]; ok {
		return next[to]
	}
	return false
}

